class Solution {
    unordered_map<long long,int> memo;
    int dfs(long long n) {
        if (n == 1) return 0;
        if (memo.count(n)) return memo[n];
        if (n % 2 == 0) return memo[n] = 1 + dfs(n/2);
        return memo[n] = 1 + min(dfs(n+1), dfs(n-1));
    }
public:
    int integerReplacement(int n) { return dfs(n); }
};

