static int dfs(long long n) {
    if (n == 1) return 0;
    if (n % 2 == 0) return 1 + dfs(n / 2);
    int a = dfs(n + 1), b = dfs(n - 1);
    return 1 + (a < b ? a : b);
}
int integerReplacement(int n) { return dfs(n); }
